// Goal: post1_self_ and post2_self_ agree, since both runs derive the same
// post-state from the same pre_self_, index, and state. The only non-trivial
// field is `page_array`; every other field is equated to pre_self_'s field in
// both runs, so transitivity is enough for them.
//
// For page_array, do a pointwise case-split on whether `i` is the modified
// index. The ensures forall (triggered on `post1_self_.page_array@[i]` and
// `post2_self_.page_array@[i]`) only fires for off-index `i`, while the
// field-wise ensures pin every Page field at `index` to a value that is the
// same in both runs (via pre_self_ or, for `state`, the input).

assert forall|i: int| 0 <= i < NUM_PAGES implies
    post1_self_.page_array@[i] =~= post2_self_.page_array@[i] by {
    if i == index as int {
        // At the modified index, every Page field is pinned to the same
        // value in both runs. Pull each field-wise ensures into the proof
        // context (both for post1 and post2) and let Page extensional
        // equality (=~=) close.
        assert(post1_self_.page_array@[i].addr =~= pre_self_.page_array@[i].addr);
        assert(post2_self_.page_array@[i].addr =~= pre_self_.page_array@[i].addr);
        assert(post1_self_.page_array@[i].is_io_page =~= pre_self_.page_array@[i].is_io_page);
        assert(post2_self_.page_array@[i].is_io_page =~= pre_self_.page_array@[i].is_io_page);
        assert(post1_self_.page_array@[i].rev_pointer =~= pre_self_.page_array@[i].rev_pointer);
        assert(post2_self_.page_array@[i].rev_pointer =~= pre_self_.page_array@[i].rev_pointer);
        assert(post1_self_.page_array@[i].ref_count =~= pre_self_.page_array@[i].ref_count);
        assert(post2_self_.page_array@[i].ref_count =~= pre_self_.page_array@[i].ref_count);
        assert(post1_self_.page_array@[i].owning_container =~= pre_self_.page_array@[i].owning_container);
        assert(post2_self_.page_array@[i].owning_container =~= pre_self_.page_array@[i].owning_container);
        assert(post1_self_.page_array@[i].mappings =~= pre_self_.page_array@[i].mappings);
        assert(post2_self_.page_array@[i].mappings =~= pre_self_.page_array@[i].mappings);
        assert(post1_self_.page_array@[i].io_mappings =~= pre_self_.page_array@[i].io_mappings);
        assert(post2_self_.page_array@[i].io_mappings =~= pre_self_.page_array@[i].io_mappings);
        assert(post1_self_.page_array@[i].state =~= state);
        assert(post2_self_.page_array@[i].state =~= state);
    } else {
        // Off-index: each run leaves the page unchanged. Mentioning
        // `post1_self_.page_array@[i]` and `post2_self_.page_array@[i]`
        // here triggers the two ensures foralls (their triggers are exactly
        // those terms), giving us equality with pre_self_'s page at i.
        assert(post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
        assert(post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);
    }
}

// Lift the pointwise Page equality to whole-sequence equality on the views.
assert(post1_self_.page_array@ =~= post2_self_.page_array@);

// Try to lift further to Array-level extensional equality (Verus' Array uses
// view-based =~= when available).
assert(post1_self_.page_array =~= post2_self_.page_array);

// Non-page_array fields: the ensures equate each to pre_self_'s field in both
// runs, so transitivity gives post1 == post2 directly.
assert(post1_self_.free_pages_4k == post2_self_.free_pages_4k);
assert(post1_self_.free_pages_2m == post2_self_.free_pages_2m);
assert(post1_self_.free_pages_1g == post2_self_.free_pages_1g);
assert(post1_self_.allocated_pages_4k == post2_self_.allocated_pages_4k);
assert(post1_self_.allocated_pages_2m == post2_self_.allocated_pages_2m);
assert(post1_self_.allocated_pages_1g == post2_self_.allocated_pages_1g);
assert(post1_self_.mapped_pages_4k == post2_self_.mapped_pages_4k);
assert(post1_self_.mapped_pages_2m == post2_self_.mapped_pages_2m);
assert(post1_self_.mapped_pages_1g == post2_self_.mapped_pages_1g);
assert(post1_self_.page_perms_4k == post2_self_.page_perms_4k);
assert(post1_self_.page_perms_2m == post2_self_.page_perms_2m);
assert(post1_self_.page_perms_1g == post2_self_.page_perms_1g);
assert(post1_self_.container_map_4k == post2_self_.container_map_4k);
assert(post1_self_.container_map_2m == post2_self_.container_map_2m);
assert(post1_self_.container_map_1g == post2_self_.container_map_1g);

// Whole-struct extensional equality (all fields agree).
assert(post1_self_ =~= post2_self_);

// r1 and r2 are both `()`.
assert(r1 == r2);
